#include <bits/stdc++.h>
#define int long long
using namespace std;
double a[15];
double sum, ans = 1;
signed main () {
	ios::sync_with_stdio (0);
	cin.tie (0), cout.tie (0);
	for (int i = 1; i <= 7; i++) {
		cin >> a[i];
		sum += a[i];
	}
	for (int i = 1; i <= 6; i++) {
		ans = ans * a[i] / (sum + 1 - i) * (double)i;
	}
	ans = ans * a[7] * 7.0;
	cout << fixed << setprecision (3) << ans;
	return 0;
}
